import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonObject_whenIsJsonObjectTrue_returnsThisAsJsonObject() {
    JsonElement element = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(element.isJsonObject()).thenReturn(true);
    // We must cast mock to JsonObject to satisfy return type.
    // Use a proxy mock for JsonObject to simulate this.
    JsonObject jsonObjectMock = mock(JsonObject.class);
    // Spy on element to return jsonObjectMock when casted
    JsonElement spyElement = spy(element);
    doReturn(true).when(spyElement).isJsonObject();
    // Trick: We want spyElement cast to JsonObject to return jsonObjectMock
    // So we create spyElement as jsonObjectMock and spy together:
    // But since getAsJsonObject does (JsonObject) this, and this is spyElement,
    // just return jsonObjectMock from spyElement.
    // Instead, override getAsJsonObject to return jsonObjectMock for testing.
    // But we test getAsJsonObject itself, so cannot override it.
    // So create a subclass of JsonElement that returns true for isJsonObject and itself as JsonObject.
    JsonElement elementSub = new JsonObject() {
      @Override
      public boolean isJsonObject() {
        return true;
      }
    };
    JsonObject result = elementSub.getAsJsonObject();
    assertSame(elementSub, result);
  }

  @Test
  void getAsJsonObject_whenIsJsonObjectFalse_throwsIllegalStateException() {
    JsonElement element = mock(JsonElement.class, withSettings().defaultAnswer(CALLS_REAL_METHODS));
    when(element.isJsonObject()).thenReturn(false);

    IllegalStateException exception = assertThrows(IllegalStateException.class, element::getAsJsonObject);
    assertTrue(exception.getMessage().startsWith("Not a JSON Object: "));
  }
}
